import { __decorate } from "tslib";
import { Component, inject } from '@angular/core';
import { moduleMetadata } from '@storybook/angular';
import { OriToastService } from './toast.service';
import { OriToastViewportComponent } from './toast-viewport.component';
import { OriButtonComponent } from '../button/button.component';
let ToastDemo = class ToastDemo {
    constructor() {
        this.position = 'top-right';
        this.toast = inject(OriToastService);
    }
};
ToastDemo = __decorate([
    Component({
        selector: 'ori-toast-demo',
        standalone: true,
        imports: [OriButtonComponent, OriToastViewportComponent],
        template: `
    <div style="display: flex; gap: 8px; flex-wrap: wrap; justify-content: center;">
      <ori-button variant="secondary" (click)="toast.info('Informations mises à jour.')">Info</ori-button>
      <ori-button variant="secondary" (click)="toast.success('Modifications enregistrées.')">Success</ori-button>
      <ori-button variant="secondary" (click)="toast.warning('Champ obligatoire manquant.')">Warning</ori-button>
      <ori-button variant="secondary" (click)="toast.danger('Échec de la connexion.')">Danger</ori-button>
      <ori-button (click)="toast.show({ title: 'Demande envoyée', description: 'Votre dossier #2026-0042 a été transmis.', variant: 'success', duration: 8000 })">
        Avec titre + 8s
      </ori-button>
      <ori-button variant="ghost" (click)="toast.show({ title: 'Persistant', description: 'Ce toast ne se ferme pas automatiquement.', duration: 0 })">
        Sans auto-dismiss
      </ori-button>
    </div>
    <ori-toast-viewport [position]="position"></ori-toast-viewport>
  `,
    })
], ToastDemo);
const meta = {
    title: 'Composants graphiques/Toast',
    component: ToastDemo,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Toasts éphémères avec auto-dismiss. Pattern service-based : `inject(OriToastService).success('…')` depuis n'importe où, et `<ori-toast-viewport>` monté une fois dans l'app.",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [ToastDemo, OriToastViewportComponent, OriButtonComponent] }),
    ],
};
export default meta;
export const Default = {
    args: { position: 'top-right' },
};
export const TopCenter = {
    args: { position: 'top-center' },
};
export const BottomRight = {
    args: { position: 'bottom-right' },
};
